package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import java.lang.reflect.Method;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTrimTest {

    private CSVFormat csvFormat;
    private Method trimMethod;

    @BeforeEach
    void setUp() throws Exception {
        csvFormat = CSVFormat.DEFAULT;
        trimMethod = CSVFormat.class.getDeclaredMethod("trim", CharSequence.class);
        trimMethod.setAccessible(true);
    }

    @Test
    void testTrim_StringWithSpaces() throws Exception {
        CharSequence input = "  abc  ";
        CharSequence result = (CharSequence) trimMethod.invoke(csvFormat, input);
        assertEquals("abc", result.toString());
        assertTrue(result instanceof String);
    }

    @Test
    void testTrim_StringNoSpaces() throws Exception {
        CharSequence input = "abc";
        CharSequence result = (CharSequence) trimMethod.invoke(csvFormat, input);
        assertSame(input, result);
    }

    @Test
    void testTrim_CharSequenceWithLeadingSpaces() throws Exception {
        CharSequence input = new CharSequence() {
            private final String str = "  abc";
            @Override public int length() { return str.length(); }
            @Override public char charAt(int index) { return str.charAt(index); }
            @Override public CharSequence subSequence(int start, int end) { return str.substring(start, end); }
            @Override public String toString() { return str; }
        };
        CharSequence result = (CharSequence) trimMethod.invoke(csvFormat, input);
        assertEquals("abc", result.toString());
        assertNotSame(input, result);
    }

    @Test
    void testTrim_CharSequenceWithTrailingSpaces() throws Exception {
        CharSequence input = new CharSequence() {
            private final String str = "abc  ";
            @Override public int length() { return str.length(); }
            @Override public char charAt(int index) { return str.charAt(index); }
            @Override public CharSequence subSequence(int start, int end) { return str.substring(start, end); }
            @Override public String toString() { return str; }
        };
        CharSequence result = (CharSequence) trimMethod.invoke(csvFormat, input);
        assertEquals("abc", result.toString());
        assertNotSame(input, result);
    }

    @Test
    void testTrim_CharSequenceWithLeadingAndTrailingSpaces() throws Exception {
        CharSequence input = new CharSequence() {
            private final String str = "  abc  ";
            @Override public int length() { return str.length(); }
            @Override public char charAt(int index) { return str.charAt(index); }
            @Override public CharSequence subSequence(int start, int end) { return str.substring(start, end); }
            @Override public String toString() { return str; }
        };
        CharSequence result = (CharSequence) trimMethod.invoke(csvFormat, input);
        assertEquals("abc", result.toString());
        assertNotSame(input, result);
    }

    @Test
    void testTrim_CharSequenceNoSpaces() throws Exception {
        CharSequence input = new CharSequence() {
            private final String str = "abc";
            @Override public int length() { return str.length(); }
            @Override public char charAt(int index) { return str.charAt(index); }
            @Override public CharSequence subSequence(int start, int end) { return str.substring(start, end); }
            @Override public String toString() { return str; }
        };
        CharSequence result = (CharSequence) trimMethod.invoke(csvFormat, input);
        assertSame(input, result);
    }

    @Test
    void testTrim_EmptyString() throws Exception {
        CharSequence input = "";
        CharSequence result = (CharSequence) trimMethod.invoke(csvFormat, input);
        assertSame(input, result);
    }

    @Test
    void testTrim_OnlySpaces() throws Exception {
        CharSequence input = "   ";
        CharSequence result = (CharSequence) trimMethod.invoke(csvFormat, input);
        assertEquals("", result.toString());
        assertNotSame(input, result);
    }
}
